import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"48. Accrued Days Off","description":"","frontmatter":{"title":"48. Accrued Days Off","eba":"Allied Health Professionals 2021-2026","topics":["hours","rosters","wages","employment"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/48-accrued-days-off.md","filePath":"ebas/allied-health/hours-of-work/48-accrued-days-off.md"}'),s={name:"ebas/allied-health/hours-of-work/48-accrued-days-off.md"};function n(i,e,l,h,u,p){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_48-accrued-days-off" tabindex="-1">48. Accrued Days Off <a class="header-anchor" href="#_48-accrued-days-off" aria-label="Permalink to &quot;48. Accrued Days Off&quot;">​</a></h1><p><strong>48.1</strong> Meaning of ‘accrued day off’ An accrued day off (ADO) results from hours of work under subclause 47.1 whereby a full-time Employee:</p><p><strong>(a)</strong> is rostered to work more than 38 hours per week;</p><p><strong>(b)</strong> is paid 38 ordinary hours;</p><p><strong>(c)</strong> the difference between the hours worked and hours paid accrues towards a paid day off; and</p><p><strong>(d)</strong> an Employee’s ordinary wage for ordinary hours is deemed to be the weekly rate prescribed in <a href="/eba/ebas/allied-health/wages/28-wages-and-wage-increases.html">clause 28</a> (Wages and Wage Increases) and set out in Appendix 2, and will be paid each week even though more or less than 38 ordinary hours are worked in that week.</p><p><strong>48.2</strong> Accrual of ADOs</p><p><strong>(a)</strong> All full-time Employees are entitled to an ADO. The Employer will not refuse a new full-time Employee an ADO.</p><p><strong>(b)</strong> The Employer will inform a new full-time Employee of the relevant department’s work arrangements and provisions regarding hours of work and taking of ADOs.</p><p><strong>(c)</strong> A full-time Employee will work an average of 38 hours per week over a four (4) week period as 19 shifts of eight (8) hours over four (4) weeks. The Employee will be paid for 38 hours for each week (that is seven (7) hours and 36 minutes per day), and will work:</p><p><strong>(i)</strong> five (5) shifts of eight (8) hours each (40 hours per week) during three (3) of the four (4) weeks; and</p><p><strong>(ii)</strong> four (4) shifts of eight (8) hours each (32 hours in total) in one (1) of the four (4) weeks.</p><p><strong>(d)</strong> For the avoidance of doubt an Employee’s ADO arrangement may provide for an Employee to take an ADO before the ADO has accrued in full.</p><p><strong>(e)</strong> An Employer and a full-time Employee may agree in writing to a different ADO arrangement to that in subclause 48.2(c). Example:</p><p>A full-time Employee works 19 shifts of 10 hours over five (5) weeks. The Employee is paid 38 hours for each week, even though the Employee works four (4) shifts of 10 hours each (40 hours per week) during four (4) of the five (5) weeks. In one (1) of the five (5) weeks, the Employee works three (3) shifts of 10 hours each (30 hours only) but is paid for 38 hours.</p><p><strong>(f)</strong> A full-time Employee may request to work their ordinary hours in a manner that does not accrue ADOs and the Employer will not unreasonably refuse the request.</p><p><strong>(g)</strong> Deductions where leave is taken</p><p><strong>(i)</strong> Where a full-time Employee takes paid leave, the leave that will be deducted from the Employee’s leave entitlement or accrual will be equal to the Employee’s ordinary hours of work for the period of leave so that the Employee will accrue credit towards their ADO.</p><p>Example: A full-time Employee’s ordinary hours are worked as 19 shifts of eight (8) hours over four (4) weeks. During a four (4) week cycle the Employee takes annual leave for one (1) week, with the Employee’s ordinary hours of work for that week being 40. The Employee is paid for 38 hours for that week of annual leave (seven (7) hours and 36 minutes per day for five (5) days), however 40 hours of leave is deducted from the Employee’s annual leave accrual for that week. The Employee will be entitled to a paid ADO of seven (7) hours and 36 minutes for the four (4) week period that included the week of annual leave, with:  five (5) hours and 36 minutes of the ADO accrued from the three (3) weeks the Employee worked; and  two (2) hours of the ADO accrued from the week of annual leave the Employee took (the two (2) hour difference between the Employee’s annual leave deduction and pay for that week.)</p><p><strong>(ii)</strong> Where a full-time Employee takes unpaid leave they will accrue the appropriate credit without pay for the ADO. Example: A full-time Employee’s ordinary hours are worked as 19 shifts of eight (8) hours over four (4) weeks. During a four (4) week cycle an Employee works 18 shifts of eight (8) hours and is on unpaid leave for one (1) shift. The Employee will be entitled to an ADO of seven (7) hours and 36 minutes for the four (4) week period that included the shift where the Employee was on unpaid leave, with:  seven (7) hours and 12 minutes of the ADO being paid, accrued from the 18 shifts the Employee worked; and  24 minutes of the ADO being unpaid, accrued from the one (1) shift the Employee was on unpaid leave.</p><p><strong>48.3</strong> Taking of ADOs and interaction with other periods</p><p><strong>(a)</strong> Unless otherwise agreed, ADOs are to be taken during the normal four (4) week or other cycle agreed to under subclause 48.2(c) in which the ADO is accrued (including leave periods).</p><p><strong>(b)</strong> Where an Employee would otherwise take their ADO in the four (4) week period in which it accrues, either the Employer or the Employee may request that the ADO not be taken in that four (4) week period, and the other party must not unreasonably refuse to agree to the request.</p><p><strong>(c)</strong> ADOs on public holidays See <a href="/eba/ebas/allied-health/leave/58-public-holidays.html">clause 58</a> (Public Holidays).</p><p><strong>48.4</strong> ADOs and termination of employment Upon termination of employment, if a full-time Employee has:</p><p><strong>(a)</strong> taken an ADO (in part or whole) in advance of accruing the necessary hours, the amount payable to the Employee will be reduced by the total ADOs or portion taken in advance; and</p><p><strong>(b)</strong> untaken ADOs (in part or whole) at the time of termination, the Employee will be paid the untaken ADOs.</p><p>Examples: 1. A full-time Employee has accrued six (6) hours towards an ADO at the time of termination. The Employer will, in addition to any other outstanding entitlements, make payment to the Employee for an amount equal to six (6) hours pay. 2. A full-time Employee has taken a full ADO of 7.6 hours, but has only accrued three (3) hours towards this ADO at the time of termination. The Employer will reduce the amount payable to the Employee upon termination by an amount equal to 4.6 hours pay.</p>',28)])])}const m=o(s,[["render",n]]);export{f as __pageData,m as default};
